### 🧠 Real-World Example: Configuration Loading

```rust
use std::env;
use std::fs;

#[derive(Debug)]
struct Config {
    port: u16,
    host: String,
}

impl Config {
    fn from_env() -> Config {
        let port = env::var("PORT")
            .expect("PORT environment variable not set")
            .parse::<u16>()
            .expect("PORT must be a valid number");

        let host = env::var("HOST")
            .expect("HOST environment variable not set");

        Config { port, host }
    }

    fn from_file(path: &str) -> Config {
        let contents = fs::read_to_string(path)
            .expect("Failed to read config file");
        // Parse JSON/YAML here...
        println!("Loaded config from: {}", path);
        Config {
            port: 8080,
            host: "localhost".to_string(),
        }
    }
}

fn main() {
    // This will panic with clear message if HOST isn't set
    let config = Config::from_env();
    println!("Config: {:?}", config);
}
```

