### 🧠 Pro Tip: Debug vs Release Behavior

```rust
use std::fs;

fn load_config() -> String {
    #[cfg(debug_assertions)]
    {
        // In debug builds, be explicit
        fs::read_to_string("dev-config.txt")
            .expect("Failed to load development config")
    }

    #[cfg(not(debug_assertions))]
    {
        // In release builds, handle gracefully
        fs::read_to_string("prod-config.txt")
            .unwrap_or_else(|_| "default_config".to_string())
    }
}
```

