### 🧠 Pro Tip: Combining with Logging

```rust
use std::fs;

fn load_config_with_logging() -> String {
    match fs::read_to_string("config.txt") {
        Ok(contents) => contents,
        Err(e) => {
            eprintln!("Config load failed: {}", e);
            // Still panic in development
