### 🧠 Pro Tip: Library vs Application Usage

```rust
// In libraries - avoid unwrap/expect, return Results
pub fn library_function() -> Result<String, Box<dyn std::error::Error>> {
    std::fs::read_to_string("data.txt")
        .map_err(|e| format!("Failed to read data: {}", e).into())
}

// In applications - expect with clear messages is okay
fn main() {
    let data = std::fs::read_to_string("data.txt")
        .expect("Application requires data.txt to run");
    println!("Data: {}", data);
}
```

