### 🧠 Real-World Example: Chain of Operations

```rust
use std::fs;
use std::io;

#[derive(Debug)]
struct ProcessedData {
    content: String,
    word_count: usize,
}

fn process_document(path: &str) -> Result<ProcessedData, io::Error> {
    // Each ? can return early if there's an error
    let raw_content = fs::read_to_string(path)?;           // Read file
    let trimmed = raw_content.trim().to_string();          // Process
    let word_count = trimmed.split_whitespace().count();   // Count words

    Ok(ProcessedData {
        content: trimmed,
        word_count,
    })
}

fn main() {
    match process_document("document.txt") {
        Ok(data) => println!("Words: {}", data.word_count),
        Err(e) => println!("Failed to process: {}", e),
    }
}
```

