### 🧠 Pro Tip: With Custom Error Types

```rust
use thiserror::Error;
use std::io;

#[derive(Error, Debug)]
pub enum MyError {
    #[error("IO error: {0}")]
    Io(#[from] io::Error),
    #[error("Parse error: {0}")]
    Parse(String),
}

fn read_and_parse(path: &str) -> Result<i32, MyError> {
    let content = std::fs::read_to_string(path)?; // Converts io::Error → MyError
    let number: i32 = content.trim().parse()
        .map_err(|_| MyError::Parse("Invalid number".to_string()))?;
    Ok(number)
}
```

