use tokio::sync::broadcast;
use tokio::sync::oneshot;
use tokio::time::{sleep, Duration};

#[derive(Debug, Clone)]
struct Command {
    id: u32,
    action: String,
    response_tx: Option<oneshot::Sender<String>>,
}

#[tokio::main]
async fn main() {
    let (cmd_tx, mut cmd_rx) = broadcast::channel(10);
    let cmd_tx_clone = cmd_tx.clone();

    // Command processor task
    tokio::spawn(async move {
        while let Ok(mut cmd) = cmd_rx.recv().await {
            println!("[Processor] Handling: {}", cmd.action);

            // Send response if requested
            if let Some(tx) = cmd.response_tx.take() {
                let _ = tx.send(format!("Processed: {}", cmd.action));
            }
        }
    });

    // Send command with response channel
    let (response_tx, response_rx) = oneshot::channel();
    let cmd = Command {
        id: 1,
        action: "update_config".to_string(),
        response_tx: Some(response_tx),
    };

    cmd_tx_clone.send(cmd).unwrap();

    if let Ok(response) = response_rx.await {
        println!("[Main] Got response: {}", response);
    }

    sleep(Duration::from_millis(100)).await;
}
