### 🧠 Pro Tip: Broadcast with Metrics

```rust
use tokio::sync::broadcast;
use std::sync::atomic::{AtomicU64, Ordering};
use std::sync::Arc;

#[derive(Debug, Clone)]
struct BroadcastMetrics {
    sent: Arc<AtomicU64>,
    received: Arc<AtomicU64>,
}

impl BroadcastMetrics {
    fn new() -> Self {
        Self {
            sent: Arc::new(AtomicU64::new(0)),
            received: Arc::new(AtomicU64::new(0)),
        }
    }

    fn record_sent(&self) {
        self.sent.fetch_add(1, Ordering::Relaxed);
    }

    fn record_received(&self) {
        self.received.fetch_add(1, Ordering::Relaxed);
    }

    fn stats(&self) -> (u64, u64) {
        (
            self.sent.load(Ordering::Relaxed),
            self.received.load(Ordering::Relaxed),
        )
    }
}

#[tokio::main]
async fn main() {
    let metrics = BroadcastMetrics::new();
    let (tx, mut rx1) = broadcast::channel(10);
    let mut rx2 = tx.subscribe();

    let metrics_clone1 = metrics.clone();
    tokio::spawn(async move {
        while let Ok(msg) = rx1.recv().await {
            metrics_clone1.record_received();
            println!("[Receiver 1] {}", msg);
        }
    });

    let metrics_clone2 = metrics.clone();
    tokio::spawn(async move {
        while let Ok(msg) = rx2.recv().await {
            metrics_clone2.record_received();
            println!("[Receiver 2] {}", msg);
        }
    });

    // Send messages
    for i in 0..5 {
        tx.send(format!("Message {}", i)).unwrap();
        metrics.record_sent();
    }

    tokio::time::sleep(tokio::time::Duration::from_millis(100)).await;

    let (sent, received) = metrics.stats();
    println!("Sent: {}, Received: {}", sent, received);
}
```

