use serde::{Deserialize, Serialize};
use std::path::Path;
use tokio::fs;

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct TurnSpan {
    pub id: String,
    pub parent_id: Option<String>,
    pub operation: String,
    pub start_time: chrono::DateTime<chrono::Utc>,
    pub end_time: Option<chrono::DateTime<chrono::Utc>>,
    pub metadata: std::collections::HashMap<String, serde_json::Value>,
    pub events: Vec<SpanEvent>,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct SpanEvent {
    pub timestamp: chrono::DateTime<chrono::Utc>,
    pub name: String,
    pub attributes: std::collections::HashMap<String, serde_json::Value>,
}

pub async fn write_span_to_disk(
    span: &TurnSpan,
    storage_base_path: &Path,
) -> Result<(), AyinError> {
    // Create directory structure: {base}/year/month/day/
    let now = chrono::Utc::now();
    let date_path = storage_base_path
        .join(now.format("%Y").to_string())
        .join(now.format("%m").to_string())
        .join(now.format("%d").to_string());

    // Ensure directory exists
    fs::create_dir_all(&date_path)
        .await
        .map_err(AyinError::Io)?;

    // Create filename with timestamp and span ID
    let filename = format!(
        "{}_{}.json",
        now.format("%H%M%S_%3f"),
        span.id
    );
    let span_file_path = date_path.join(filename);

    // Serialize with pretty printing for human readability
    let span_json = serde_json::to_string_pretty(span)
        .map_err(AyinError::Serialization)?;

    // Write atomically using temp file + rename
    let temp_path = span_file_path.with_extension("tmp");
    fs::write(&temp_path, span_json)
        .await
        .map_err(AyinError::Io)?;

    fs::rename(&temp_path, &span_file_path)
        .await
        .map_err(AyinError::Io)?;

    tracing::trace!("Persisted span {} to {}", span.id, span_file_path.display());
    Ok(())
}
```

