### 🧠 Pro Tip: Compression for Large Spans

```rust
use tokio::io::AsyncWriteExt;

pub async fn write_span_to_disk_compressed(
    span: &TurnSpan,
    storage_path: &Path,
) -> Result<(), AyinError> {
    let span_file = storage_path.join(format!("span_{}.json.gz", span.id));

    let span_json = serde_json::to_string(&span)
        .map_err(AyinError::Serialization)?;

    let mut encoder = flate2::write::GzEncoder::new(
        Vec::new(),
        flate2::Compression::default(),
    );
    encoder.write_all(span_json.as_bytes())
        .map_err(AyinError::Io)?;
    let compressed_data = encoder.finish()
        .map_err(AyinError::Io)?;

    let temp_path = span_file.with_extension("tmp");
    fs::write(&temp_path, compressed_data)
        .await
        .map_err(AyinError::Io)?;

    fs::rename(&temp_path, &span_file)
        .await
        .map_err(AyinError::Io)?;

    Ok(())
}
```

