### 🧠 Pro Tip: Batch Writing for Performance

```rust
use tokio::sync::mpsc;
use tokio::time::interval;

pub struct SpanWriter {
    tx: mpsc::UnboundedSender<WriteSpanRequest>,
}

struct WriteSpanRequest {
    span: TurnSpan,
    storage_path: PathBuf,
    response_tx: Option<oneshot::Sender<Result<(), AyinError>>>,
}

impl SpanWriter {
    pub fn new(storage_base_path: PathBuf) -> Self {
        let (tx, mut rx) = mpsc::unbounded_channel();

        tokio::spawn(async move {
            let mut batch = Vec::new();
            let mut interval = interval(tokio::time::Duration::from_millis(100));

            loop {
                tokio::select! {
                    request = rx.recv() => {
                        if let Some(req) = request {
                            batch.push(req);
                            // Write immediately if batch is full
                            if batch.len() >= 10 {
                                Self::write_batch(&mut batch, &storage_base_path).await;
                            }
                        } else {
                            // Channel closed, write remaining
                            Self::write_batch(&mut batch, &storage_base_path).await;
                            break;
                        }
                    }
                    _ = interval.tick() => {
                        if !batch.is_empty() {
                            Self::write_batch(&mut batch, &storage_base_path).await;
                        }
                    }
                }
            }
        });

        Self { tx }
    }

    async fn write_batch(
        batch: &mut Vec<WriteSpanRequest>,
        storage_base_path: &Path,
    ) {
        for request in batch.drain(..) {
            let result = write_span_to_disk(&request.span, storage_base_path).await;
            if let Some(tx) = request.response_tx {
                let _ = tx.send(result);
            }
        }
    }
}
```

