pub struct SessionContext {
    pub session_id: String,
    pub session_span_id: String,  // Root span for entire session
    pub user_id: String,
    pub model: String,
    pub priority: PriorityLevel,
}

#[derive(Debug, Clone)]
pub struct TurnMetadata {
    pub turn_type: String,  // "chat", "tool_use", "reasoning"
    pub model: String,
    pub priority: PriorityLevel,
}

pub async fn emit_turn_start_span(
    session_span_id: &str,
    user_message_id: &str,
    metadata: TurnMetadata,
) -> Result<String, AyinError> {
    let turn_span_id = uuid::Uuid::new_v4().to_string();

    // Create the span object
    let span = TurnSpan {
        id: turn_span_id.clone(),
        parent_id: Some(session_span_id.to_string()),
        operation: "assistant_turn".to_string(),
        start_time: chrono::Utc::now(),
        end_time: None,
        metadata: hashmap! {
            "user_message_id".to_string() => json!(user_message_id),
            "turn_type".to_string() => json!(metadata.turn_type),
            "model".to_string() => json!(metadata.model),
            "priority".to_string() => json!(metadata.priority as i32),
            "created_at".to_string() => json!(chrono::Utc::now().to_rfc3339()),
        },
        events: vec![],
    };

    // Emit to SSE stream for frontend
    emit_sse_event(SseEvent::TurnStart {
        span: span.clone(),
        session_span_id: session_span_id.to_string(),
    }).await?;

    // Persist for debugging/analysis
    if let Err(e) = write_span_to_disk(&span, &get_ayin_storage_path()).await {
        tracing::warn!("Failed to persist turn start span: {}", e);
        // Don't fail the main flow though
    }

    tracing::info!(
        session_span_id = %session_span_id,
        turn_span_id = %turn_span_id,
        user_message_id = %user_message_id,
        "Emitted turn start span"
    );

    Ok(turn_span_id)
}
