// In sse.ts or similar
class SSEHandler {
    constructor() {
        this.pendingTurns = new Map();
        this.startTimeoutWatchdog();
    }

    handleEvent(event) {
        if (event.type === 'copilot_response') {
            this.pendingTurns.set(event.turn_span_id, {
                startTime: Date.now(),
                lastActivity: Date.now(),
                chunksReceived: 0
            });
        }

        if (event.type === 'done') {
            this.pendingTurns.delete(event.turn_span_id);
        }
    }

    startTimeoutWatchdog() {
        setInterval(() => {
            const now = Date.now();
            for (const [turnId, state] of this.pendingTurns) {
                // If no activity for 30 seconds, assume done
                if (now - state.lastActivity > 30000) {
                    console.warn(`Timeout recovery for turn ${turnId}`);
                    this.emitSyntheticDone(turnId);
                    this.pendingTurns.delete(turnId);
                }
            }
        }, 5000);
    }

    emitSyntheticDone(turnId) {
        const syntheticDone = {
            type: 'done',
            turn_span_id: turnId,
            success: false,
            message: 'Timeout - process may have failed'
        };
        this.dispatchEvent(syntheticDone);
    }
}
```

