#### 🧱 Core Timeout Recovery System

```javascript
// In webshell-ui/src/lib/sse.ts
export class CopilotSSEHandler {
    constructor() {
        this.activeTurns = new Map();
        this.setupTimeoutRecovery();
        this.setupChunkCountRecovery();
    }

    handleServerEvent(event) {
        switch(event.type) {
            case 'copilot_response':
                this.trackNewTurn(event.turn_span_id);
                this.dispatchToUI(event);
                break;

            case 'chunk':
                this.updateTurnActivity(event.turn_span_id);
                this.dispatchToUI(event);
                break;

            case 'done':
                this.completeTurn(event.turn_span_id);
                this.dispatchToUI(event);
                break;

            default:
                this.dispatchToUI(event);
        }
    }

    trackNewTurn(turnId) {
        this.activeTurns.set(turnId, {
            startTime: Date.now(),
            lastChunkTime: Date.now(),
            chunkCount: 0,
            expectedChunks: null,
            timeoutHandle: setTimeout(() => {
                this.handleTurnTimeout(turnId);
            }, 45000) // 45 second timeout
        });
    }

    updateTurnActivity(turnId) {
        const turn = this.activeTurns.get(turnId);
        if (turn) {
            turn.lastChunkTime = Date.now();
            turn.chunkCount++;
            // Reset timeout
            clearTimeout(turn.timeoutHandle);
            turn.timeoutHandle = setTimeout(() => {
                this.handleTurnTimeout(turnId);
            }, 45000);
        }
    }

    completeTurn(turnId) {
        const turn = this.activeTurns.get(turnId);
        if (turn) {
            clearTimeout(turn.timeoutHandle);
            this.activeTurns.delete(turnId);
        }
    }

    handleTurnTimeout(turnId) {
        console.warn(`[SSE] Turn timeout detected for ${turnId}`);
        this.activeTurns.delete(turnId);

        // Emit synthetic done event
        const syntheticDone = {
            type: 'done',
            turn_span_id: turnId,
            success: false,
            message: 'Backend process timed out or crashed',
            recovered: true
        };

        this.dispatchToUI(syntheticDone);
    }
}
```

