### 🧠 Recovery Strategies in the UI

```svelte
<!-- In CopilotDrawer.svelte or similar -->
<script>
    let copilotMessages = [];
    let pendingTurns = new Set();

    function handleCopilotResponse(event) {
        const message = {
            id: event.turn_span_id,
            type: 'assistant',
            content: '',
            isStreaming: true,
            turnSpanId: event.turn_span_id
        };
        copilotMessages = [...copilotMessages, message];
        pendingTurns.add(event.turn_span_id);
    }

    function handleChunk(event) {
        const message = copilotMessages.find(m => m.turnSpanId === event.turn_span_id);
        if (message) {
            message.content += event.content;
        }
    }

    function handleDone(event) {
        const message = copilotMessages.find(m => m.turnSpanId === event.turn_span_id);
        if (message) {
            message.isStreaming = false;
            message.completed = true;
            message.success = event.success;
            message.errorMessage = event.success ? null : event.message;
        }
        pendingTurns.delete(event.turn_span_id);
    }

    // Watchdog for stuck turns
    let watchdogInterval = setInterval(() => {
        const now = Date.now();
        for (const turnId of pendingTurns) {
            const message = copilotMessages.find(m => m.turnSpanId === turnId);
            if (message && now - message.lastUpdateTime > 60000) {
                // Force completion after 1 minute
                handleDone({
                    type: 'done',
                    turn_span_id: turnId,
                    success: false,
                    message: 'UI timeout - backend may be unresponsive'
                });
            }
        }
    }, 10000);
</script>
```

