// Additional recovery based on chunk patterns
function setupChunkCountRecovery() {
    const chunkPatterns = new Map(); // turnId -> {firstChunkTime, chunkCount}

    setInterval(() => {
        for (const [turnId, pattern] of chunkPatterns) {
            const rate = pattern.chunkCount / (Date.now() - pattern.firstChunkTime);
            // If chunk rate drops to near zero, assume stuck
            if (rate < 0.01 && Date.now() - pattern.lastChunkTime > 10000) {
                console.warn(`Chunk rate recovery for turn ${turnId}`);
                handleTurnTimeout(turnId);
                chunkPatterns.delete(turnId);
            }
        }
    }, 3000);
}
