pub async fn generate_assistant_response(
    context: &ChainContext,
    strategy_result: StrategyResult,
) -> Result<AssistantResponse, ResponseError> {
    let start_time = std::time::Instant::now();

    // Track key timing milestones
    let mut timing_builder = ResponseTimingBuilder::new();

    // Generate the actual response content
    let (content, token_count) = format_response_content(
        &strategy_result,
        &context.user_message,
    ).await?;

    timing_builder.mark_formatting_complete();

    // Calculate performance metrics
    let timing = timing_builder.build(start_time.elapsed())?;

    // Create the response
