) -> Result<(), AyinError> {
    let emit_time = chrono::Utc::now();

    let span = TurnSpanEvent {
        span_id: generate_span_id(),
        parent_span_id: Some(turn_span_id.to_string()),
        event_type: "assistant_response".to_string(),
        timestamp: emit_time,
        metadata: json!({
            // Content metrics
            "response_length_chars": response.content.len(),
            "response_length_tokens": response.token_count,
            "model_used": response.model,
            "strategy_used": response.strategy,

            // Timing data - THE GOLD! ✨
            "timing": {
                "total_response_time_ms": timing.total_duration.as_millis(),
                "first_token_latency_ms": timing.first_token_latency.as_millis(),
                "tokens_per_second": timing.tokens_per_second,
                "queue_time_ms": timing.queue_time.as_millis(),
                "strategy_selection_time_ms": timing.strategy_selection_time.as_millis(),
                "processing_breakdown": {
                    "reasoning_time_ms": timing.processing_breakdown.reasoning_time.as_millis(),
                    "tool_execution_time_ms": timing.processing_breakdown.tool_execution_time.as_millis(),
                    "model_call_time_ms": timing.processing_breakdown.model_call_time.as_millis(),
                    "formatting_time_ms": timing.processing_breakdown.formatting_time.as_millis(),
                }
            },

            // Quality metrics
            "quality_metrics": {
                "coherence_score": response.quality_metrics.coherence_score,
                "relevance_score": response.quality_metrics.relevance_score,
                "confidence_level": response.quality_metrics.confidence_level,
                "helpfulness_score": response.quality_metrics.helpfulness_score,
                "safety_flags": response.quality_metrics.safety_flags,
            },

            // Metadata
            "citation_count": response.citations.len(),
            "emit_timestamp": emit_time.to_rfc3339(),
            "response_hash": calculate_content_hash(&response.content),
