        },
    };

    // Emit to observability system
    emit_span_event(span, &get_ayin_context()).await?;

    // Also persist for analysis (but be smart about storage)
    if should_persist_response_span(&response, &timing) {
        write_span_to_disk(&span, &get_ayin_storage_path()).await?;
    }

    tracing::info!(
        turn_span_id = %turn_span_id,
        total_time_ms = %timing.total_duration.as_millis(),
        tokens_per_second = %timing.tokens_per_second,
        "Emitted assistant response span"
    );

    Ok(())
}

fn should_persist_response_span(
    response: &AssistantResponse,
    timing: &ResponseTiming,
) -> bool {
    // Persist slow responses for analysis
    timing.total_duration.as_millis() > 2000 ||
    // Persist low-quality responses
    response.quality_metrics.coherence_score < 0.7 ||
    // Persist responses with safety flags
    !response.quality_metrics.safety_flags.is_empty() ||
    // Persist for sampling
    rand::random::<f32>() < 0.01 // 1% sample rate
}
