```rust
// In the response streaming handler
impl AssistantResponseSpan {
    pub async fn record_first_token(&mut self) -> Result<(), AyinError> {
        let first_token_time = chrono::Utc::now();
        let latency = first_token_time.signed_duration_since(self.start_time);

        self.timing.first_token_latency = Some(std::time::Duration::from_millis(
            latency.num_milliseconds() as u64
        ));

        // Emit timing update
        emit_span_event(SseEvent::ResponseTimingUpdate {
            span_id: self.id.clone(),
            timing: self.timing.clone(),
        }).await?;

        Ok(())
    }

    pub async fn record_token(&mut self) -> Result<(), AyinError> {
        self.timing.token_count += 1;
        self.timing.chunk_count += 1;

        // Emit periodic updates for long responses
        if self.timing.token_count % 50 == 0 {
            emit_span_event(SseEvent::ResponseProgress {
                span_id: self.id.clone(),
                tokens_processed: self.timing.token_count,
                chunks_processed: self.timing.chunk_count,
            }).await?;
        }

        Ok(())
    }

    pub async fn complete(&mut self, success: bool) -> Result<(), AyinError> {
        let end_time = chrono::Utc::now();
        self.end_time = Some(end_time);

        let total_duration = end_time.signed_duration_since(self.start_time);
        self.timing.total_response_time = Some(std::time::Duration::from_millis(
            total_duration.num_milliseconds() as u64
        ));

        // Calculate tokens per second if we have tokens
        if self.timing.token_count > 0 && total_duration.num_milliseconds() > 0 {
            let tps = (self.timing.token_count as f64) / 
                     (total_duration.num_milliseconds() as f64 / 1000.0);
            self.timing.tokens_per_second = Some(tps);
        }

        // Emit completion event
        emit_span_event(SseEvent::AssistantResponseDone {
            span_id: self.id.clone(),
            timing: self.timing.clone(),
            success,
            end_time: end_time.to_rfc3339(),
        }).await?;

        // Persist final span
        write_span_to_disk(self, &get_ayin_storage_path()).await?;

        tracing::info!(
            span_id = %self.id,
            token_count = %self.timing.token_count,
            total_time_ms = %total_duration.num_milliseconds(),
            tokens_per_second = ?self.timing.tokens_per_second,
            success = %success,
            "Completed assistant response span"
        );

        Ok(())
    }
}
