#[derive(Debug, Clone)]
pub struct AssistantResponseSpan {
    pub id: String,
    pub parent_id: Option<String>,
    pub operation: String,
    pub start_time: chrono::DateTime<chrono::Utc>,
    pub end_time: Option<chrono::DateTime<chrono::Utc>>,
    pub timing: ResponseTiming,
    pub metadata: HashMap<String, serde_json::Value>,
}

#[derive(Debug, Clone)]
pub struct ResponseTiming {
    pub first_token_time: Option<chrono::DateTime<chrono::Utc>>,
    pub total_generation_time: Option<std::time::Duration>,
    pub token_count: u32,
    pub tokens_per_second: f64,
}

// Called at different stages of response generation
pub async fn emit_assistant_response_span(
    turn_span_id: &str,
    metadata: ResponseMetadata,
) -> Result<String, AyinError> {
    let span_id = uuid::Uuid::new_v4().to_string();

    let span = AssistantResponseSpan {
        id: span_id.clone(),
        parent_id: Some(turn_span_id.to_string()),
        operation: "assistant_response".to_string(),
        start_time: chrono::Utc::now(),
        end_time: None,
        timing: ResponseTiming {
            first_token_time: None,
            total_generation_time: None,
            token_count: 0,
            tokens_per_second: 0.0,
        },
        metadata: hashmap! {
            "model".to_string() => json!(metadata.model),
            "max_tokens".to_string() => json!(metadata.max_tokens),
            "temperature".to_string() => json!(metadata.temperature),
            "streaming".to_string() => json!(metadata.streaming),
        },
    };

    tracing::info!(
        parent_span_id = %turn_span_id,
        response_span_id = %span_id,
        model = %metadata.model,
        "Starting assistant response generation"
    );

    emit_event(Event::AssistantResponseStart {
        span: span.clone(),
    }).await?;

    Ok(span_id)
}

// Called when first token arrives
pub async fn emit_first_token(
    response_span_id: &str,
    start_time: chrono::DateTime<chrono::Utc>,
) -> Result<(), AyinError> {
    let now = chrono::Utc::now();
    let time_to_first_token = now.signed_duration_since(start_time);

    emit_event(Event::FirstToken {
        response_span_id: response_span_id.to_string(),
        timestamp: now,
        time_to_first_token: time_to_first_token.num_milliseconds(),
    }).await?;

    tracing::debug!(
        response_span_id = %response_span_id,
        ttft_ms = %time_to_first_token.num_milliseconds(),
        "First token generated"
    );

    Ok(())
}

// Called when response is complete
pub async fn emit_response_complete(
    response_span_id: &str,
    token_count: u32,
    start_time: chrono::DateTime<chrono::Utc>,
) -> Result<(), AyinError> {
    let end_time = chrono::Utc::now();
    let total_time = end_time.signed_duration_since(start_time);
    let tokens_per_second = if total_time.num_milliseconds() > 0 {
        (token_count as f64) / (total_time.num_milliseconds() as f64 / 1000.0)
    } else {
        0.0
    };

    emit_event(Event::ResponseComplete {
        response_span_id: response_span_id.to_string(),
        timestamp: end_time,
        token_count,
        total_generation_time_ms: total_time.num_milliseconds(),
        tokens_per_second,
    }).await?;

    tracing::info!(
        response_span_id = %response_span_id,
        token_count = %token_count,
        generation_time_ms = %total_time.num_milliseconds(),
        tokens_per_second = %.2,
        "Assistant response generation complete"
    );

    Ok(())
}
```

