### 🧠 Real-World Usage Example

```rust
// In the response generation pipeline
async fn generate_assistant_response(
    context: &ChainContext,
    prompt: &str,
) -> Result<String, ResponseError> {
    // 1. Emit response span start
    let response_span_id = emit_assistant_response_span(
        &context.turn_span_id,
        ResponseMetadata {
            model: context.model.clone(),
            max_tokens: 2048,
            temperature: 0.7,
            streaming: true,
            response_type: "chat_completion".to_string(),
        }
    ).await
    .map_err(ResponseError::Observability)?;

    let start_time = chrono::Utc::now();
    let mut token_count = 0;

    // 2. Stream tokens and track timing
    let mut response_stream = call_llm_api_streaming(prompt, &context).await?;

    // 3. Track first token timing
    let mut first_token_emitted = false;

    let mut full_response = String::new();
    while let Some(chunk) = response_stream.next().await {
        let chunk = chunk.map_err(ResponseError::LlmApi)?;

        if !first_token_emitted {
            emit_first_token(&response_span_id, start_time).await?;
            first_token_emitted = true;
        }

        token_count += count_tokens(&chunk);
        full_response.push_str(&chunk);

        // Emit chunk to frontend
        emit_event(Event::ResponseChunk {
            response_span_id: response_span_id.clone(),
            content: chunk,
        }).await?;
    }

    // 4. Emit completion with full timing data
    emit_response_complete(&response_span_id, token_count, start_time).await?;

    Ok(full_response)
}
```

