pub struct AyinSpanGuard {
    span: tracing::Span,
    trace_context: TraceparentContext,
}

impl AyinSpanGuard {
    pub fn new(trace_id: &str, operation: &str) -> Self {
        let span_id = generate_span_id();
        let span = tracing::info_span!(operation, 
            trace_id = %trace_id,
            span_id = %span_id
        );

        let trace_context = TraceparentContext {
            trace_id: trace_id.to_string(),
            span_id,
            parent_id: None,
            sampled: true,
            trace_state: None,
        };

        Self { span, trace_context }
    }

    pub fn to_headers(&self) -> HeaderMap {
        generate_traceparent_headers(
            &self.trace_context.trace_id,
            &self.trace_context.span_id,
        )
    }
}
